-- =========================================
--  Initial Region Seed Data (PostgreSQL)
-- =========================================
-- Insert region
INSERT INTO regions (region_id, name, image, created_at, updated_at)
VALUES (
        1,
        'IJsselland',
        decode(
            '',
            'base64'
        ),
        NOW(),
        NOW()
    ),
    (
        2,
        'Twente',
        decode(
            '',
            'base64'
        ),
        NOW(),
        NOW()
    ) ON CONFLICT (region_id) DO NOTHING;
-- Map municipalities
INSERT INTO regions_municipality (region_id, municipality_id)
VALUES (1, 1),
    (1, 2),
    (1, 3) ON CONFLICT DO NOTHING;
-- Reset sequence to avoid conflicts
SELECT setval(
        'regions_region_id_seq',
        (
            SELECT MAX(region_id)
            FROM regions
        )
    );